    def __init__(self, type_, value=None, op=None, left=None, right=None, operand=None):
        self.type = type_
        self.value = value
        self.op = op
        self.left = left
        self.right = right
        self.operand = operand

    def __repr__(self):
        if self.type == 'number':
            return f'Number({self.value})'
        elif self.type == 'binop':
            return f'BinOp({self.op}, {self.left}, {self.right})'
        elif self.type == 'unary':
            return f'Unary({self.op}, {self.operand})'
        return f'ASTNode({self.type})'


class _Parser:
    def __init__(self, expression):
        self.tokens = self._tokenize(expression)
        self.pos = 0
        self.current_token = self.tokens[0] if self.tokens else None

    def _tokenize(self, expression):
        tokens = []
        i = 0
        while i < len(expression):
            char = expression[i]

            if char.isspace():
                i += 1
                continue

            if char in '+-*/()':
                tokens.append(('op', char))
                i += 1
                continue

            if char.isdigit():
                num_str = ''
                while i < len(expression) and (expression[i].isdigit() or expression[i] == '.'):
                    num_str += expression[i]
                    i += 1
                tokens.append(('number', float(num_str)))
                continue

            raise ValueError(f"Invalid character '{char}'")

        if not tokens:
            raise ValueError("Empty expression")

        tokens.append(('end', None))
        return tokens

    def _consume(self):
        if self.pos >= len(self.tokens):
            raise ValueError("Unexpected end of expression")
        token = self.current_token
        self.pos += 1
        if self.pos < len(self.tokens):
            self.current_token = self.tokens[self.pos]
        else:
            self.current_token = ('end', None)
        return token

    def _expect(self, token_type, value=None):
        token = self._consume()
        if token[0] != token_type or (value is not None and token[1] != value):
            raise ValueError(f"Expected {token_type} {value}, got {token}")
        return token

    def _parse_expression(self, min_precedence=1):
        left = self._parse_term(min_precedence)

        while self.current_token[0] == 'op':
            op = self.current_token[1]
            if op == '+' or op == '-':
                precedence = 1
            elif op == '*' or op == '/':
                precedence = 2
            else:
                break

            if precedence < min_precedence:
                break

            self._consume()
            right = self._parse_term(precedence + 1)
            left = ASTNode('binop', op=op, left=left, right=right)

        return left

    def _parse_term(self, min_precedence=2):
        left = self._parse_factor(min_precedence)

        while self.current_token[0] == 'op':
            op = self.current_token[1]
            if op == '*' or op == '/':
                precedence = 2
            else:
                break

            if precedence < min_precedence:
                break

            self._consume()
            right = self._parse_factor(precedence + 1)
            if op == '*':
                left = ASTNode('binop', op='*', left=left, right=right)
            else:
                left = ASTNode('binop', op='/', left=left, right=right)

        return left

    def _parse_factor(self, min_precedence=2):
        token = self.current_token

        if token[0] == 'op':
            if token[1] == '(':
                self._consume()
                expr = self._parse_expression()
                self._expect('op', ')')
                return expr

            elif token[1] == '+' or token[1] == '-':
                if token[1] == '-':
                    self._consume()
                    operand = self._parse_factor(min_precedence)
                    return ASTNode('unary', op='-', operand=operand)

                self._consume()
                operand = self._parse_factor(min_precedence)
                return operand

            raise ValueError(f"Unexpected operator {token[1]}")

        if token[0] == 'number':
            self._consume()
            return ASTNode('number', value=token[1])

        raise ValueError("Expected number or operator")


def parse(expression):
    parser = _Parser(expression)
    ast = parser._parse_expression()
    if parser.current_token[0] != 'end':
        raise ValueError("Unexpected token at end of expression")
    return ast


def evaluate(node):
    if node.type == 'number':
        return node.value
    elif node.type == 'binop':
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == '+':
            return left_val + right_val
        elif node.op == '-':
            return left_val - right_val
        elif node.op == '*':
            return left_val * right_val
        elif node.op == '/':
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val

        raise ValueError(f"Unknown operator {node.op}")
    elif node.type == 'unary':
        operand_val = evaluate(node.operand)

        if node.op == '-':
            return -operand_val

        raise ValueError(f"Unknown unary operator {node.op}")

    raise ValueError(f"Unknown node type {node.type}")
